changes.old_code:
validate() {
  if (!this.name || this.name.length < 2) {
    return { valid: false, error: 'Name must be at least 2 characters' };
  }
  if (!this.email || !this.email.includes('@')) {
    return { valid: false, error: 'Invalid email address' };
  }
  return { valid: true };
}

changes.new_code:
validate() {
  // Validate name - must be at least 2 characters
  if (!this.name || this.name.length < 2) {
    return { valid: false, error: 'Name must be at least 2 characters', field: 'name' };
  }
  // Validate email - must contain @ symbol
  if (!this.email || !this.email.includes('@')) {
    return { valid: false, error: 'Invalid email address', field: 'email' };
  }
  // Validate role - must be one of the allowed roles
  const allowedRoles = ['user', 'admin', 'moderator'];
  if (!allowedRoles.includes(this.role)) {
    return { valid: false, error: 'Invalid role', field: 'role' };
  }
  return { valid: true };
}
